import React, { useEffect, useMemo, useState } from 'react';
import './StubPages.css';

const API_URL = 'http://localhost:5000/api';

const PatientsList = ({ onNavigate }) => {
  const [patients, setPatients] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchPatients = async () => {
    try {
      setLoading(true);
      setError('');

      const response = await fetch(`${API_URL}/patients`);
      const result = await response.json();

      const patientData = Array.isArray(result)
        ? result
        : Array.isArray(result.data)
        ? result.data
        : Array.isArray(result.patients)
        ? result.patients
        : [];

      setPatients(patientData);
    } catch (err) {
      setError('Unable to load patients.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPatients();
  }, []);

  const filteredPatients = useMemo(() => {
    const q = searchTerm.toLowerCase().trim();
    if (!q) return patients;

    return patients.filter((patient) => {
      const fullName =
        `${patient.firstName || ''} ${patient.lastName || ''}`.toLowerCase();
      const email = (patient.email || '').toLowerCase();
      const phone = (patient.phone || '').toLowerCase();
      const gender = (patient.gender || '').toLowerCase();

      return (
        fullName.includes(q) ||
        email.includes(q) ||
        phone.includes(q) ||
        gender.includes(q)
      );
    });
  }, [patients, searchTerm]);

  return (
    <div className="page">
      <div className="page-header-row">
        <div>
          <h2>Patients List</h2>
          <p>View and search all registered patients</p>
        </div>
        <button className="action-btn" onClick={() => onNavigate('patient-registration')}>
          + Register Patient
        </button>
      </div>

      <div className="table-card">
        <div className="toolbar-row">
          <input
            type="text"
            className="search-input"
            placeholder="Search by name, email, phone, gender"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button className="secondary-btn" onClick={fetchPatients}>
            Refresh
          </button>
        </div>

        {loading ? (
          <p>Loading patients...</p>
        ) : error ? (
          <p className="error-text">{error}</p>
        ) : filteredPatients.length === 0 ? (
          <p>No patients found.</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>#</th>
                <th>Patient Name</th>
                <th>Email</th>
                <th>Phone</th>
                <th>Gender</th>
                <th>Age</th>
              </tr>
            </thead>
            <tbody>
              {filteredPatients.map((patient, index) => (
                <tr key={patient.id || patient._id || index}>
                  <td>{index + 1}</td>
                  <td>{`${patient.firstName || ''} ${patient.lastName || ''}`.trim() || 'N/A'}</td>
                  <td>{patient.email || 'N/A'}</td>
                  <td>{patient.phone || 'N/A'}</td>
                  <td>{patient.gender || 'N/A'}</td>
                  <td>{patient.age || 'N/A'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default PatientsList;
